package fizeau

import (
	"context"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/routehealth"
)

const (
	// defaultHealthProbeInterval is the interval between background aliveness
	// probes when ServiceOptions.HealthProbeInterval is zero.
	defaultHealthProbeInterval = 60 * time.Second
	// defaultHealthSignalTTL is the maximum age of a probe result used to
	// populate routing.Inputs.ProbeUnreachable when HealthSignalTTL is zero.
	defaultHealthSignalTTL = 10 * time.Minute
	// startupProbeTotalTimeout bounds the total wall-clock time spent on
	// startup aliveness probes, regardless of provider count.
	startupProbeTotalTimeout = 5 * time.Second
)

// ProviderAlivenessProber reports whether a provider endpoint is reachable.
// Returns true if reachable, false if not. The prober must respect ctx for
// cancellation.
type ProviderAlivenessProber func(ctx context.Context, provider, baseURL string) bool

// alivenessEndpoint describes one provider endpoint to probe.
type alivenessEndpoint struct {
	provider string
	baseURL  string
}

func (s *service) healthProbeInterval() time.Duration {
	if s.opts.HealthProbeInterval > 0 {
		return s.opts.HealthProbeInterval
	}
	return defaultHealthProbeInterval
}

func (s *service) healthSignalTTL() time.Duration {
	if s.opts.HealthSignalTTL > 0 {
		return s.opts.HealthSignalTTL
	}
	return defaultHealthSignalTTL
}

// alivenessEndpoints enumerates the non-cloud provider endpoints that
// should be probed. Only providers whose billing type indicates fixed/local
// billing are included; cloud subscription providers are excluded.
func (s *service) alivenessEndpoints() []alivenessEndpoint {
	if s.opts.ServiceConfig == nil {
		return nil
	}
	var endpoints []alivenessEndpoint
	seen := make(map[string]struct{})
	for _, name := range s.opts.ServiceConfig.ProviderNames() {
		entry, ok := s.opts.ServiceConfig.Provider(name)
		if !ok || entry.ConfigError != "" {
			continue
		}
		if !providerTypeUsesFixedBilling(entry.Type) {
			continue
		}
		if entry.BaseURL != "" {
			key := name + "|" + entry.BaseURL
			if _, dup := seen[key]; !dup {
				seen[key] = struct{}{}
				endpoints = append(endpoints, alivenessEndpoint{provider: name, baseURL: entry.BaseURL})
			}
		}
		for _, ep := range entry.Endpoints {
			if ep.BaseURL == "" {
				continue
			}
			key := name + "|" + ep.BaseURL
			if _, dup := seen[key]; !dup {
				seen[key] = struct{}{}
				endpoints = append(endpoints, alivenessEndpoint{provider: name, baseURL: ep.BaseURL})
			}
		}
	}
	return endpoints
}

// startupAlivenessProbe probes all configured non-cloud providers synchronously
// at service startup. The total probe time is bounded by startupProbeTotalTimeout
// regardless of provider count.
func (s *service) startupAlivenessProbe(ctx context.Context) {
	if s.providerProbe == nil {
		return
	}
	endpoints := s.alivenessEndpoints()
	if len(endpoints) == 0 {
		return
	}
	prober := s.opts.AlivenessProber
	if prober == nil {
		prober = tcpAlivenessProber
	}
	runStartupAlivenessProbes(ctx, endpoints, s.providerProbe, prober, startupProbeTotalTimeout)
	s.persistProbeStore()
}

// runStartupAlivenessProbes probes each endpoint sequentially within totalTimeout.
// It is exported as a standalone function for direct testing.
func runStartupAlivenessProbes(
	ctx context.Context,
	endpoints []alivenessEndpoint,
	store *routehealth.ProbeStore,
	prober ProviderAlivenessProber,
	totalTimeout time.Duration,
) {
	if len(endpoints) == 0 || store == nil || prober == nil {
		return
	}
	probeCtx := ctx
	if totalTimeout > 0 {
		var cancel context.CancelFunc
		probeCtx, cancel = context.WithTimeout(ctx, totalTimeout)
		defer cancel()
	}
	now := time.Now().UTC()
	for _, ep := range endpoints {
		if probeCtx.Err() != nil {
			break
		}
		success := prober(probeCtx, ep.provider, ep.baseURL)
		if probeCtx.Err() != nil {
			success = false
		}
		store.RecordProbe(ep.provider, "", success, now)
	}
}

func (s *service) persistProbeStore() {
	if s == nil || s.providerProbe == nil || s.opts.PersistRouteHealth == "" {
		return
	}
	_ = s.providerProbe.Save(s.opts.PersistRouteHealth)
}

// startAlivenessProbeLoop spawns the goroutine that periodically re-probes
// configured non-cloud providers. The goroutine is tied to QuotaRefreshContext
// (or context.Background()) so server callers can cancel it on shutdown.
func (s *service) startAlivenessProbeLoop() {
	if s.providerProbe == nil {
		return
	}
	endpoints := s.alivenessEndpoints()
	if len(endpoints) == 0 {
		return
	}
	ctx := s.opts.QuotaRefreshContext
	if ctx == nil {
		ctx = context.Background()
	}
	prober := s.opts.AlivenessProber
	if prober == nil {
		prober = tcpAlivenessProber
	}
	store := s.providerProbe
	interval := s.healthProbeInterval()
	persistPath := s.opts.PersistRouteHealth
	go runAlivenessProbeLoop(ctx, endpoints, store, prober, interval, nil, nil, persistPath)
}

// runAlivenessProbeLoop periodically re-probes each endpoint whose last probe
// is older than interval. now and sleep are seams for deterministic tests;
// pass nil for production defaults.
func runAlivenessProbeLoop(
	ctx context.Context,
	endpoints []alivenessEndpoint,
	store *routehealth.ProbeStore,
	prober ProviderAlivenessProber,
	interval time.Duration,
	now func() time.Time,
	sleep func(ctx context.Context, d time.Duration) bool,
	persistPath string,
) {
	if now == nil {
		now = time.Now
	}
	if sleep == nil {
		sleep = alivenessLoopSleep
	}
	if interval <= 0 {
		interval = defaultHealthProbeInterval
	}
	for {
		t := now().UTC()
		for _, ep := range endpoints {
			if ctx.Err() != nil {
				return
			}
			if !store.ProbeNeeded(ep.provider, "", t, interval) {
				continue
			}
			probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
			success := prober(probeCtx, ep.provider, ep.baseURL)
			cancel()
			store.RecordProbe(ep.provider, "", success, t)
		}
		if persistPath != "" {
			_ = store.Save(persistPath)
		}
		if !sleep(ctx, interval) {
			return
		}
	}
}

func alivenessLoopSleep(ctx context.Context, d time.Duration) bool {
	if d <= 0 {
		return ctx.Err() == nil
	}
	timer := time.NewTimer(d)
	defer timer.Stop()
	select {
	case <-ctx.Done():
		return false
	case <-timer.C:
		return true
	}
}

// tcpAlivenessProber tests endpoint reachability via a TCP connect probe.
func tcpAlivenessProber(ctx context.Context, _, baseURL string) bool {
	addr := extractHostPort(baseURL)
	if addr == "" {
		return false
	}
	d := net.Dialer{}
	conn, err := d.DialContext(ctx, "tcp", addr)
	if err != nil {
		return false
	}
	_ = conn.Close()
	return true
}

// extractHostPort extracts host:port from a base URL, adding the scheme's
// default port when none is specified.
func extractHostPort(baseURL string) string {
	baseURL = strings.TrimSpace(baseURL)
	if baseURL == "" {
		return ""
	}
	if !strings.Contains(baseURL, "://") {
		baseURL = "http://" + baseURL
	}
	u, err := url.Parse(baseURL)
	if err != nil {
		return ""
	}
	host := u.Host
	if host == "" {
		return ""

		return 0
	}
	if policy.MinPower > 0 && power < policy.MinPower {
		// Mirror the engine scorer: materially underpowered routes should not
		// win just because they are cheap.
		return -float64(policy.MinPower-power) * 12
	}
	if policy.MaxPower > 0 && power > policy.MaxPower {
		return -float64(power - policy.MaxPower)
	}
	return 0
}

func positiveScorePart(v float64) float64 {
	if v > 0 {
		return v
	}
	return 0
}

type routeSnapshotCandidateKey struct {
	Provider       string
	Endpoint       string
	ServerInstance string
	Model          string
}

func routeSnapshotCandidateIndex(snapshot modelsnapshot.ModelSnapshot) map[routeSnapshotCandidateKey]modelsnapshot.KnownModel {
	if len(snapshot.Models) == 0 {
		return nil
	}
	out := make(map[routeSnapshotCandidateKey]modelsnapshot.KnownModel, len(snapshot.Models))
	for _, row := range snapshot.Models {
		key := routeSnapshotCandidateKey{
			Provider:       strings.TrimSpace(row.Provider),
			Endpoint:       strings.TrimSpace(row.EndpointName),
			ServerInstance: strings.TrimSpace(serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance)),
			Model:          strings.TrimSpace(row.ID),
		}
		if key.Provider == "" || key.Model == "" {
			continue
		}
		if _, exists := out[key]; exists {
			continue
		}
		out[key] = row
	}
	return out
}

func routeSnapshotEvidenceForCandidate(candidate RouteCandidate, snapshot modelsnapshot.ModelSnapshot) (modelsnapshot.KnownModel, bool) {
	index := routeSnapshotCandidateIndex(snapshot)
	if len(index) == 0 {
		return modelsnapshot.KnownModel{}, false
	}
	provider := strings.TrimSpace(candidate.Provider)
	endpoint := strings.TrimSpace(candidate.Endpoint)
	serverInstance := strings.TrimSpace(candidate.ServerInstance)
	model := strings.TrimSpace(candidate.Model)
	if base, ep, ok := splitEndpointProviderRef(provider); ok {
		provider = base
		if endpoint == "" {
			endpoint = ep
		}
	}
	keys := []routeSnapshotCandidateKey{{
		Provider:       provider,
		Endpoint:       endpoint,
		ServerInstance: serverInstance,
		Model:          model,
	}}
	if endpoint == "" {
		keys = append(keys, routeSnapshotCandidateKey{
			Provider:       provider,
			ServerInstance: serverInstance,
			Model:          model,
		})
	}
	if serverInstance == "" {
		keys = append(keys, routeSnapshotCandidateKey{
			Provider: provider,
			Endpoint: endpoint,
			Model:    model,
		})
		if endpoint == "" {
			keys = append(keys, routeSnapshotCandidateKey{
				Provider: provider,
				Model:    model,
			})
		}
	}
	for _, key := range keys {
		if row, ok := index[key]; ok {
			return row, true
		}
	}
	for _, row := range snapshot.Models {
		rowProvider := strings.TrimSpace(row.Provider)
		rowEndpoint := strings.TrimSpace(row.EndpointName)
		rowServerInstance := strings.TrimSpace(serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance))
		if rowProvider != provider || strings.TrimSpace(row.ID) != model {
			continue
		}
		if endpoint != "" && rowEndpoint != endpoint {
			continue
		}
		if serverInstance != "" && rowServerInstance != serverInstance {
			continue
		}
		return row, true
	}
	return modelsnapshot.KnownModel{}, false
}

func applyRouteSnapshotEvidence(candidate *RouteCandidate, row modelsnapshot.KnownModel) {
	if candidate == nil {
		return
	}
	if candidate.ServerInstance == "" {
		candidate.ServerInstance = strings.TrimSpace(serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance))
	}
	candidate.SourceStatus = string(row.Status)
	candidate.AutoRoutable = row.AutoRoutable
	candidate.ExactPinOnly = row.ExactPinOnly
	candidate.ExclusionReason = row.ExclusionReason
	candidate.ActualCashSpend = row.ActualCashSpend
	candidate.EffectiveCost = row.EffectiveCost
	candidate.EffectiveCostSource = row.EffectiveCostSource
	candidate.ModelDiscoveryFreshnessAt = row.DiscoveredAt.UTC()
	candidate.ModelDiscoveryFreshnessSource = string(row.DiscoveredVia)
	candidate.HealthFreshnessAt = row.HealthFreshnessAt.UTC()
	candidate.HealthFreshnessSource = row.HealthFreshnessSource
	candidate.QuotaFreshnessAt = row.QuotaFreshnessAt.UTC()
	candidate.QuotaFreshnessSource = row.QuotaFreshnessSource
}

func applyRouteSnapshotEvidenceToStatus(candidate *RouteCandidateStatus, row modelsnapshot.KnownModel) {
	if candidate == nil {
		return
	}
	candidate.SourceStatus = string(row.Status)
	candidate.AutoRoutable = row.AutoRoutable
	candidate.ExactPinOnly = row.ExactPinOnly
	candidate.ExclusionReason = row.ExclusionReason
	candidate.Power = row.Power
	candidate.ContextLength = row.ContextWindow
	candidate.CostInputPerMTok = row.CostInputPerM
	candidate.CostOutputPerMTok = row.CostOutputPerM
	candidate.RecentLatencyMS = float64(row.RecentP50Latency.Milliseconds())
	candidate.QuotaRemaining = row.QuotaRemaining
	candidate.ActualCashSpend = row.ActualCashSpend
	candidate.EffectiveCost = row.EffectiveCost
	candidate.EffectiveCostSource = row.EffectiveCostSource
	candidate.HealthFreshnessAt = row.HealthFreshnessAt.UTC()
	candidate.HealthFreshnessSource = row.HealthFreshnessSource
	candidate.QuotaFreshnessAt = row.QuotaFreshnessAt.UTC()
	candidate.QuotaFreshnessSource = row.QuotaFreshnessSource
	candidate.ModelDiscoveryFreshnessAt = row.DiscoveredAt.UTC()
	candidate.ModelDiscoveryFreshnessSource = string(row.DiscoveredVia)
}

func (s *service) annotateRouteDecisionSnapshotEvidence(decision *RouteDecision, snapshot modelsnapshot.ModelSnapshot) {
	if s == nil || decision == nil {
		return
	}
	decision.SnapshotCapturedAt = snapshot.AsOf
	for i := range decision.Candidates {
		if row, ok := routeSnapshotEvidenceForCandidate(decision.Candidates[i], snapshot); ok {
			applyRouteSnapshotEvidence(&decision.Candidates[i], row)
		}
		decision.Candidates[i].SnapshotCapturedAt = snapshot.AsOf
	}
}

func (s *service) annotateRouteDecisionEvidence(decision *RouteDecision) {
	if s == nil || decision == nil {
		return
	}
	decision.Utilization = s.routeUtilizationEvidence(decision.Provider, decision.ServerInstance, decision.Endpoint, decision.Model)
	for i := range decision.Candidates {
		decision.Candidates[i].Utilization = s.routeUtilizationEvidence(
			decision.Candidates[i].Provider,
			decision.Candidates[i].ServerInstance,
			decision.Candidates[i].Endpoint,
			decision.Candidates[i].Model,
		)
		s.annotateProbeEvidence(&decision.Candidates[i])
	}
}

// annotateProbeEvidence populates LastProbeAt and LastProbeSuccess on a
// RouteCandidate from the service's probe store when a record is available.
func (s *service) annotateProbeEvidence(c *RouteCandidate) {
	if s == nil || s.providerProbe == nil || c == nil {
		return
	}
	provider := strings.TrimSpace(c.Provider)
	if provider == "" {
		return
	}
	endpoint := strings.TrimSpace(c.Endpoint)
	if base, ep, ok := splitEndpointProviderRef(provider); ok {
		provider = base
		if endpoint == "" {
			endpoint = ep
		}
	}
	if r, ok := s.providerProbe.LastProbe(provider, endpoint); ok {
		c.LastProbeAt = r.LastProbeAt
		c.LastProbeSuccess = r.LastProbeSuccess
		return
	}
	if endpoint != "" {
		if r, ok := s.providerProbe.LastProbe(provider, ""); ok {
			c.LastProbeAt = r.LastProbeAt
			c.LastProbeSuccess = r.LastProbeSuccess
		}
	}
}

func (s *service) routeUtilizationEvidence(provider, serverInstance, endpoint, model string) RouteUtilizationState {
	if s == nil || s.routeUtilization == nil {
		return RouteUtilizationState{}
	}
	keyProvider := strings.TrimSpace(provider)
	keyServerInstance := strings.TrimSpace(serverInstance)
	keyEndpoint := strings.TrimSpace(endpoint)
	if base, ep, ok := splitEndpointProviderRef(keyProvider); ok {
		keyProvider = base
		if keyEndpoint == "" {
			keyEndpoint = ep
		}
	}
	if keyServerInstance == "" {
		keyServerInstance = keyEndpoint
	}
	sample, ok := s.routeUtilization.Sample(keyProvider, keyServerInstance, model)
	if !ok && keyEndpoint != "" && keyEndpoint != keyServerInstance {
		sample, ok = s.routeUtilization.Sample(keyProvider, keyEndpoint, model)
	}
	if !ok {
		return RouteUtilizationState{}
	}
	return routeUtilizationStateFromSample(sample)
}

func routeUtilizationStateFromSample(sample utilization.EndpointUtilization) RouteUtilizationState {
	out := RouteUtilizationState{
		Source:     string(sample.Source),
		Freshness:  string(sample.Freshness),
		ObservedAt: sample.ObservedAt,
	}
	if sample.ActiveRequests != nil {
		out.ActiveRequests = utilization.Int(*sample.ActiveRequests)
	}
	if sample.QueuedRequests != nil {
		out.QueuedRequests = utilization.Int(*sample.QueuedRequests)
	}
	if sample.MaxConcurrency != nil {
		out.MaxConcurrency = utilization.Int(*sample.MaxConcurrency)
	}
	if sample.CacheUsage != nil {
		v := *sample.CacheUsage
		out.CachePressure = &v
	}
	if out.CachePressure == nil && sample.MaxConcurrency != nil && *sample.MaxConcurrency > 0 {
		total := 0
		if sample.ActiveRequests != nil {
			total += *sample.ActiveRequests
		}
		if sample.QueuedRequests != nil {
			total += *sample.QueuedRequests
		}
		pressure := float64(total) / float64(*sample.MaxConcurrency)
		out.CachePressure = &pressure
	}
	return out
}

