// Config is the top-level agent configuration.
type Config struct {
	// Providers is a map of named provider configurations.
	Providers map[string]ProviderConfig `yaml:"providers"`

	// Endpoints is the endpoint-first provider schema. Each entry is expanded
	// into an internal generated provider during finalization.
	Endpoints []EndpointConfig `yaml:"endpoints,omitempty"`

	// Routing configures default model-first resolution behavior.
	Routing RoutingConfig `yaml:"routing,omitempty"`

	// Backends is a map of named backend pool configurations.
	Backends map[string]BackendPoolConfig `yaml:"backends,omitempty"`

	// DefaultBackend is the name of the default backend pool. When set, it
	// takes precedence over Default for runs that do not name a provider
	// or backend explicitly.
	DefaultBackend string `yaml:"default_backend,omitempty"`

	// ModelCatalog configures the optional external manifest path.
	ModelCatalog ModelCatalogConfig `yaml:"model_catalog,omitempty"`

	Tools ToolsConfig `yaml:"tools,omitempty"`

	// Anchors enables anchored read output and the anchor_edit tool for CLI runs.
	Anchors bool `yaml:"anchors,omitempty"`

	// Skills configures progressive-disclosure SKILL.md discovery.
	Skills SkillsConfig `yaml:"skills,omitempty"`

	// Telemetry configures OTel export enablement and runtime-specific
	// pricing keyed by provider system and resolved model.
	Telemetry telemetry.Config `yaml:"telemetry,omitempty"`

	// Default is the name of the default provider. If empty, uses the first.
	Default string `yaml:"default"`

	// MaxIterations limits agent loop iterations.
	MaxIterations int `yaml:"max_iterations"`

	// ReasoningByteLimit is the maximum bytes of pure reasoning_content
	// allowed before the stream is aborted. Default is 256KB.
	// Set to 0 for unlimited (same pattern as max_iterations).
	ReasoningByteLimit int `yaml:"reasoning_byte_limit"`

	// CompactionPercent scales the effective context window used to trigger
	// automatic compaction. Range 1-100. 0 or absent = use default (95%).
	// The actual trigger threshold = context_window × percent/100 - reserve_tokens.
	CompactionPercent int `yaml:"compaction_percent,omitempty"`

	// SessionLogDir is where session logs are written.
	SessionLogDir string `yaml:"session_log_dir"`

	// Preset is the system prompt preset name.
	Preset string `yaml:"preset"`

	// ImportedFrom records the last import source for drift detection.
	ImportedFrom *ImportMetadata `yaml:"imported_from,omitempty"`

	// Legacy flat fields for backwards compatibility.
	LegacyProvider string `yaml:"provider,omitempty"`
	LegacyBaseURL  string `yaml:"base_url,omitempty"`
	LegacyAPIKey   string `yaml:"api_key,omitempty"`
	LegacyModel    string `yaml:"model,omitempty"`

	warnings       []string          `yaml:"-"`
	providerErrors map[string]string `yaml:"-"`
}

// Defaults returns a Config with sensible defaults.
func Defaults() Config {
	return Config{
		MaxIterations:      100,
		SessionLogDir:      DefaultSessionLogDir(),
		Preset:             "default",
		ReasoningByteLimit: agent.DefaultReasoningByteLimit,
	}
}

// Load reads configuration from .fizeau/config.yaml (project) and
// ~/.config/fizeau/config.yaml (global), with env var expansion.
// Project config overrides global config. If no config files exist,
// returns defaults.
func Load(workDir string) (*Config, error) {
	cfg := Defaults()

	// Try global config first, then project config (project wins)
	var paths []string
	if home, err := os.UserHomeDir(); err == nil {
		paths = append(paths, GlobalConfigPath(home))
	}
	paths = append(paths, ProjectConfigPath(workDir))

	for _, p := range paths {
		data, err := safefs.ReadFile(p)
		if err != nil {
			continue
		}
		expanded := expandEnvVars(string(data))
		if err := rejectLegacyProviderReasoningKeys([]byte(expanded)); err != nil {
			return nil, fmt.Errorf("config: parsing %s: %w", p, err)
		}
		if err := yaml.Unmarshal([]byte(expanded), &cfg); err != nil {
			return nil, fmt.Errorf("config: parsing %s: %w", p, err)
		}
	}

	}
	textOut := runBuiltCLI(t, exe, workDir, testEnvWithHome(home, map[string]string{
		"PATH":             "",
		"FIZEAU_CACHE_DIR": cacheDir,
	}), "--work-dir", workDir, "route-status", "--policy", "cheap", "--model", "qwen3.5-27b")
	require.Equal(t, 0, textOut.exitCode, "stdout=%s stderr=%s", textOut.stdout, textOut.stderr)
	for _, want := range []string{
		"snapshot_captured_at",
		"actual_cash_spend",
		"effective_cost",
		"effective_cost_source",
		"model_discovery_freshness_at",
		"source_status",
	} {
		require.Contains(t, textOut.stdout, want, "route-status text output missing %q: %s", want, textOut.stdout)
	}
}

// TestRouteStatus_ShowsEligibleCandidatesPerIntent asserts that
// `fiz route-status --policy <p>` calls service.ResolveRoute and
// renders the engine's full candidate trace for the requested policy
// input, including the structured power-policy evidence and candidate
// score components. Per ADR-005 §5.
func TestRouteStatus_ShowsEligibleCandidatesPerIntent(t *testing.T) {
	exe := buildAgentCLI(t)
	workDir := t.TempDir()
	home := t.TempDir()

	// Discover a local power-5 model so the native harness has at least one
	// eligible candidate under the cheap policy. Subscription harnesses
	// also surface candidates but go ineligible without quota state,
	// exercising both eligible and ineligible code paths.
	healthy := newCountedOpenAIServer(t, http.StatusOK, "qwen3.5-27b", "ok")
	healthy.setModels("qwen3.5-27b")

	writeTempConfig(t, workDir, `
providers:
  vidar:
    type: lmstudio
    base_url: `+healthy.baseURL()+`
    api_key: test
    model: qwen3.5-27b
`)

	out := runBuiltCLI(t, exe, workDir, testEnvWithHome(home, nil), "--work-dir", workDir, "route-status", "--policy", "cheap", "--json")
	require.Equal(t, 0, out.exitCode, "stdout=%s stderr=%s", out.stdout, out.stderr)

	type component struct {
		Cost            float64 `json:"cost"`
		LatencyMS       float64 `json:"latency_ms"`
		Utilization     float64 `json:"utilization"`
		SuccessRate     float64 `json:"success_rate"`
		Capability      float64 `json:"capability"`
		ContextHeadroom int     `json:"context_headroom"`
		StickyAffinity  float64 `json:"sticky_affinity"`
	}
	type candidate struct {
		Harness       string    `json:"harness"`
		Provider      string    `json:"provider"`
		Model         string    `json:"model"`
		Score         float64   `json:"score"`
		ContextLength int       `json:"context_length"`
		ContextSource string    `json:"context_source"`
		Components    component `json:"components"`
		Eligible      bool      `json:"eligible"`
		FilterReason  string    `json:"filter_reason"`
		Reason        string    `json:"reason"`
		Winner        bool      `json:"winner"`
	}
	var parsed struct {
		Policy      string `json:"policy"`
		PowerPolicy struct {
			PolicyName string `json:"policy_name"`
			MinPower   int    `json:"min_power"`
			MaxPower   int    `json:"max_power"`
		} `json:"power_policy"`
		Winner     *candidate  `json:"winner"`
		Candidates []candidate `json:"candidates"`
	}
	require.NoError(t, json.Unmarshal([]byte(out.stdout), &parsed), "stdout=%s", out.stdout)
	assert.Equal(t, "cheap", parsed.Policy)
	assert.Equal(t, "cheap", parsed.PowerPolicy.PolicyName)
	require.NotEmpty(t, parsed.Candidates, "engine must surface its candidate trace; stdout=%s", out.stdout)

	// Every candidate carries the score-component bundle (cost, latency_ms,
	// success_rate, capability) plus an eligible bool and a filter_reason
	// string that explains rankings without parsing free-form Reason text.
	sawIneligibleWithReason := false
	sawIneligible := false
	for _, c := range parsed.Candidates {
		// Eligible candidates must name a concrete model. Ineligible
		// subscription-harness candidates (claude / codex / gemini)
		// surface with Model:"" in environments without their CLI on
		// PATH (e.g., CI); FilterReason is the explanation there.
		if c.Eligible {
			assert.NotEmpty(t, c.Model, "eligible candidate must name a concrete model: %+v", c)
		}
		// Components is structured (not free-form); reading the named axes
		// proves the wire shape matches AC §2.
		_ = c.Components.Cost
		_ = c.Components.LatencyMS
		_ = c.Components.Utilization
		_ = c.Components.SuccessRate
		_ = c.Components.Capability
		_ = c.Components.ContextHeadroom
		_ = c.Components.StickyAffinity
		_ = c.ContextLength
		_ = c.ContextSource
		if !c.Eligible {
			sawIneligible = true
			if c.FilterReason != "" {
				sawIneligibleWithReason = true
			}
		}
	}
	if sawIneligible {
		assert.True(t, sawIneligibleWithReason,
			"at least one ineligible candidate must carry a non-empty filter_reason; got %+v",
			parsed.Candidates)
	}
}

